// CDM Community Church — VBS 2026 Landing Page
// Injected at BODY_END via Wix custom embed
// Matches CDM site design: black hero, Barlow Condensed display, white nav

(function () {
  'use strict';

  // Only run on /vbs page OR when ?vbs=1 query param is present
  var path = window.location.pathname.replace(/\/+$/, '') || '/';
  var hasParam = window.location.search.indexOf('vbs=1') !== -1;
  if (path !== '/vbs' && !hasParam) return;

  // Immediately suppress any other page overlays
  var suppressStyle = document.createElement('style');
  suppressStyle.id = 'cdm-vbs-suppress';
  suppressStyle.textContent = '#cdm-home-root,#cdm-sof-root,#cdm-join-root,#cdm-give-root{display:none!important}';
  document.head.appendChild(suppressStyle);


  var FORM_URL = 'https://docs.google.com/forms/d/e/1FAIpQLScsR2SR3NVvyiIY31vvhKiog3sYEZ9WBAD9xIZfnMjgK3rr2A/viewform';
  var LOGO_URL = 'data:image/jpeg;base64,';

  // FOUC hide
  var foucStyle = document.createElement('style');
  foucStyle.id = 'cdm-vbs-fouc';
  foucStyle.textContent = 'body{opacity:0!important;}';
  document.head.appendChild(foucStyle);

  // Anti-scale
  var antiScale = document.createElement('style');
  antiScale.id = 'cdm-vbs-anti-scale';
  antiScale.textContent = '#SITE_CONTAINER,#site-root,[data-testid="mesh-layout"]{transform:none!important;zoom:1!important;}';
  document.head.appendChild(antiScale);

  function waitAndInject() {
    var siteRoot = document.querySelector('#site-root');
    if (!siteRoot || siteRoot.children.length === 0) {
      setTimeout(waitAndInject, 100);
      return;
    }
    inject();
  }

  function inject() {
    if (document.getElementById('cdm-vbs-root')) return;

    var f = document.getElementById('cdm-vbs-fouc');
    if (f) f.parentNode.removeChild(f);

    // Fonts
    if (!document.getElementById('cdm-vbs-fonts')) {
      var fontLink = document.createElement('link');
      fontLink.id = 'cdm-vbs-fonts';
      fontLink.rel = 'stylesheet';
      fontLink.href = 'https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@700;900&family=Barlow:wght@400;500;600&display=swap';
      document.head.appendChild(fontLink);
    }

    var style = document.createElement('style');
    style.textContent = `
      #cdm-vbs-root * { box-sizing: border-box; margin: 0; padding: 0; }
      #cdm-vbs-root {
        font-family: 'Barlow', sans-serif;
        background: #fff;
        color: #000;
        min-height: 100vh;
        overflow-x: hidden;
      }

      /* ── NAV (matches CDM exactly) ── */
      .vbs-nav {
        background: #fff;
        border-bottom: 1px solid #E0E0E0;
        padding: 0 56px;
        height: 76px;
        display: flex;
        align-items: center;
        justify-content: space-between;
        position: sticky;
        top: 0;
        z-index: 100;
      }
      .vbs-nav-logo img {
        height: 48px;
        width: auto;
        display: block;
      }
      .vbs-nav-links {
        display: flex;
        align-items: center;
        gap: 36px;
        list-style: none;
      }
      .vbs-nav-links a {
        text-decoration: none;
        color: #000;
        font-size: 13px;
        font-weight: 600;
        letter-spacing: 0.12em;
        text-transform: uppercase;
        transition: color 0.2s;
      }
      .vbs-nav-links a:hover { color: #1E2A5E; }
      .vbs-nav-give {
        background: #1E2A5E;
        color: #fff !important;
        padding: 10px 24px;
        border-radius: 100px;
        font-size: 13px;
        font-weight: 700;
        letter-spacing: 0.12em;
        text-transform: uppercase;
        text-decoration: none;
        transition: opacity 0.2s;
      }
      .vbs-nav-give:hover { opacity: 0.85; }

      /* ── HERO (black, massive type — matches CDM hero) ── */
      .vbs-hero {
        background: #000;
        min-height: 88vh;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        text-align: center;
        padding: 80px 56px;
        position: relative;
        overflow: hidden;
      }
      .vbs-hero-eyebrow {
        font-size: 11px;
        font-weight: 600;
        letter-spacing: 0.22em;
        text-transform: uppercase;
        color: #666;
        margin-bottom: 24px;
      }
      .vbs-hero h1 {
        font-family: 'Barlow Condensed', sans-serif;
        font-weight: 900;
        font-size: clamp(72px, 13vw, 160px);
        text-transform: uppercase;
        letter-spacing: -0.02em;
        line-height: 0.88;
        color: #fff;
        margin-bottom: 28px;
      }
      .vbs-hero h1 .navy { color: #1E2A5E; }
      .vbs-hero-sub {
        font-size: clamp(16px, 2vw, 20px);
        color: rgba(255,255,255,0.55);
        max-width: 520px;
        margin: 0 auto 44px;
        line-height: 1.6;
      }
      .vbs-hero-btns {
        display: flex;
        gap: 16px;
        flex-wrap: wrap;
        justify-content: center;
      }
      .btn-primary {
        background: #1E2A5E;
        color: #fff;
        font-family: 'Barlow Condensed', sans-serif;
        font-weight: 900;
        font-size: 16px;
        letter-spacing: 0.12em;
        text-transform: uppercase;
        padding: 16px 40px;
        border-radius: 100px;
        text-decoration: none;
        transition: opacity 0.2s;
        display: inline-block;
      }
      .btn-primary:hover { opacity: 0.85; }
      .btn-outline {
        background: transparent;
        color: #fff;
        font-family: 'Barlow Condensed', sans-serif;
        font-weight: 900;
        font-size: 16px;
        letter-spacing: 0.12em;
        text-transform: uppercase;
        padding: 14px 40px;
        border-radius: 100px;
        border: 2px solid rgba(255,255,255,0.3);
        text-decoration: none;
        transition: border-color 0.2s;
        display: inline-block;
      }
      .btn-outline:hover { border-color: #fff; }

      /* ── DETAILS STRIP (white bg, black text, navy left-border accents) ── */
      .vbs-details {
        background: #F5F5F5;
        border-top: 3px solid #1E2A5E;
        display: flex;
        flex-wrap: wrap;
        justify-content: center;
      }
      .vbs-detail-item {
        display: flex;
        flex-direction: column;
        padding: 28px 40px;
        border-right: 1px solid #E0E0E0;
        min-width: 180px;
      }
      .vbs-detail-item:last-child { border-right: none; }
      .vbs-detail-label {
        font-size: 11px;
        font-weight: 600;
        letter-spacing: 0.18em;
        text-transform: uppercase;
        color: #666;
        margin-bottom: 6px;
      }
      .vbs-detail-value {
        font-family: 'Barlow Condensed', sans-serif;
        font-weight: 700;
        font-size: 20px;
        color: #000;
        line-height: 1.2;
      }

      /* ── SECTIONS ── */
      .vbs-section {
        padding: 96px 56px;
        max-width: 1200px;
        margin: 0 auto;
      }
      .vbs-section-eyebrow {
        font-size: 11px;
        font-weight: 600;
        letter-spacing: 0.22em;
        text-transform: uppercase;
        color: #666;
        margin-bottom: 16px;
        display: block;
      }
      .vbs-section h2 {
        font-family: 'Barlow Condensed', sans-serif;
        font-weight: 900;
        font-size: clamp(40px, 6vw, 72px);
        text-transform: uppercase;
        letter-spacing: -0.01em;
        line-height: 0.95;
        color: #000;
        margin-bottom: 48px;
      }
      .vbs-section h2 .navy { color: #1E2A5E; }

      /* Steps grid */
      .vbs-steps {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
        gap: 2px;
        background: #E0E0E0;
        border: 2px solid #E0E0E0;
      }
      .vbs-step {
        background: #fff;
        padding: 36px 28px;
      }
      .vbs-step-num {
        font-family: 'Barlow Condensed', sans-serif;
        font-weight: 900;
        font-size: 56px;
        line-height: 1;
        color: #E0E0E0;
        margin-bottom: 16px;
      }
      .vbs-step h3 {
        font-family: 'Barlow Condensed', sans-serif;
        font-weight: 900;
        font-size: 22px;
        text-transform: uppercase;
        letter-spacing: 0.04em;
        color: #000;
        margin-bottom: 10px;
      }
      .vbs-step p {
        font-size: 15px;
        color: #666;
        line-height: 1.6;
      }

      /* ── CTA SECTION (black, like hero) ── */
      .vbs-cta {
        background: #000;
        padding: 96px 56px;
        text-align: center;
      }
      .vbs-cta h2 {
        font-family: 'Barlow Condensed', sans-serif;
        font-weight: 900;
        font-size: clamp(48px, 8vw, 96px);
        text-transform: uppercase;
        letter-spacing: -0.02em;
        line-height: 0.9;
        color: #fff;
        margin-bottom: 36px;
      }
      .vbs-cta h2 .navy { color: #1E2A5E; }
      .vbs-cta-note {
        margin-top: 20px;
        font-size: 13px;
        color: rgba(255,255,255,0.35);
        letter-spacing: 0.08em;
      }

      /* ── FOOTER ── */
      .vbs-footer {
        background: #fff;
        border-top: 1px solid #E0E0E0;
        padding: 40px 56px;
        display: flex;
        align-items: center;
        justify-content: space-between;
        flex-wrap: wrap;
        gap: 16px;
      }
      .vbs-footer-logo img { height: 36px; width: auto; }
      .vbs-footer-info {
        font-size: 13px;
        color: #666;
        line-height: 1.7;
        text-align: right;
      }
      .vbs-footer-info a { color: #1E2A5E; text-decoration: none; }

      /* ── HAMBURGER ── */
      .vbs-hamburger {
        display: none;
        background: none;
        border: none;
        cursor: pointer;
        padding: 8px;
        flex-direction: column;
        gap: 5px;
      }
      .vbs-hamburger span {
        display: block;
        width: 24px;
        height: 2px;
        background: #000;
        border-radius: 2px;
        transition: transform 0.25s, opacity 0.25s;
      }

      /* ── MOBILE ── */
      @media (max-width: 768px) {
        .vbs-nav { padding: 0 24px; }
        .vbs-nav-links { display: none; }
        .vbs-hamburger { display: flex; }
        .vbs-hero { padding: 60px 24px; min-height: 80vh; }
        .vbs-details { flex-direction: column; }
        .vbs-detail-item { border-right: none; border-bottom: 1px solid #E0E0E0; padding: 20px 24px; }
        .vbs-section { padding: 64px 24px; }
        .vbs-cta { padding: 72px 24px; }
        .vbs-footer { padding: 32px 24px; flex-direction: column; align-items: flex-start; }
        .vbs-footer-info { text-align: left; }
      }
    `;
    document.head.appendChild(style);

    var wrapper = document.createElement('div');
    wrapper.id = 'cdm-vbs-root';
    wrapper.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;z-index:2147483647;overflow-y:auto;overflow-x:hidden;background:#fff;transform:none!important;zoom:1!important;';

    wrapper.innerHTML = `
      <!-- NAV -->
      <nav class="vbs-nav">
        <a class="vbs-nav-logo" href="/">
          <img src="${LOGO_URL}" alt="CDM Community Church">
        </a>
        <ul class="vbs-nav-links">
          <li><a href="/">Home</a></li>
          <li><a href="/about">Statement of Faith</a></li>
          <li><a href="/join-us">Join Us</a></li>
          <li><a href="/cdmsports">CDM Sports</a></li>
          <li><a href="/give" class="vbs-nav-give">Give</a></li>
        </ul>
        <button class="vbs-hamburger" aria-label="Open menu" aria-expanded="false">
          <span></span><span></span><span></span>
        </button>
      </nav>

      <!-- HERO -->
      <section class="vbs-hero">
        <p class="vbs-hero-eyebrow">CDM Community Church &nbsp;&middot;&nbsp; Summer 2026</p>
        <h1>VACATION<br><span class="navy">BIBLE</span><br>SCHOOL</h1>
        <p class="vbs-hero-sub">A fun-filled day of learning, games, and community for children of all ages. Free for all families.</p>
        <div class="vbs-hero-btns">
          <a class="btn-primary" href="${FORM_URL}" target="_blank" rel="noopener">Register Now — It's Free</a>
          <a class="btn-outline" href="#details">Event Details</a>
        </div>
      </section>

      <!-- DETAILS STRIP -->
      <div class="vbs-details" id="details">
        <div class="vbs-detail-item">
          <span class="vbs-detail-label">Date</span>
          <span class="vbs-detail-value">June 6, 2026</span>
        </div>
        <div class="vbs-detail-item">
          <span class="vbs-detail-label">Time</span>
          <span class="vbs-detail-value">9:30 AM – 2:30 PM</span>
        </div>
        <div class="vbs-detail-item">
          <span class="vbs-detail-label">Location</span>
          <span class="vbs-detail-value">Kendall Indian Hammocks Park<br>Shelter #5</span>
        </div>
        <div class="vbs-detail-item">
          <span class="vbs-detail-label">Address</span>
          <span class="vbs-detail-value">11395 SW 79 St<br>Miami, FL 33173</span>
        </div>
        <div class="vbs-detail-item">
          <span class="vbs-detail-label">Cost</span>
          <span class="vbs-detail-value">Free</span>
        </div>
      </div>

      <!-- HOW TO REGISTER -->
      <div style="background:#fff;">
        <div class="vbs-section">
          <span class="vbs-section-eyebrow">Getting Started</span>
          <h2>HOW TO<br><span class="navy">REGISTER</span></h2>
          <div class="vbs-steps">
            <div class="vbs-step">
              <div class="vbs-step-num">01</div>
              <h3>Tap Register</h3>
              <p>Click the Register Now button above to open the official Google Form registration.</p>
            </div>
            <div class="vbs-step">
              <div class="vbs-step-num">02</div>
              <h3>Fill Out Form</h3>
              <p>Complete all sections — child info, emergency contacts, medical authorization, and photo consent.</p>
            </div>
            <div class="vbs-step">
              <div class="vbs-step-num">03</div>
              <h3>Submit</h3>
              <p>Hit submit. Optionally request an email copy of your completed form for your records.</p>
            </div>
            <div class="vbs-step">
              <div class="vbs-step-num">04</div>
              <h3>See You June 6</h3>
              <p>Arrive by 9:30 AM at Kendall Indian Hammocks Park Shelter #5. Registration is always free.</p>
            </div>
          </div>
        </div>
      </div>

      <!-- CTA -->
      <section class="vbs-cta">
        <h2>READY<br>TO <span class="navy">JOIN</span><br>US?</h2>
        <a class="btn-primary" href="${FORM_URL}" target="_blank" rel="noopener" style="font-size:18px;padding:20px 56px;">Register Now</a>
        <p class="vbs-cta-note">ONE FORM PER CHILD &nbsp;&middot;&nbsp; TAKES ABOUT 2 MINUTES</p>
      </section>

      <!-- FOOTER -->
      <footer class="vbs-footer">
        <a class="vbs-footer-logo" href="/">
          <img src="${LOGO_URL}" alt="CDM Community Church">
        </a>
        <div class="vbs-footer-info">
          12811 SW 134th Ct, Miami, FL 33186<br>
          <a href="tel:+13054915648">(305) 491-5648</a>
          &nbsp;&middot;&nbsp;
          <a href="mailto:info@cdmchurchmiami.com">info@cdmchurchmiami.com</a><br>
          &copy; 2026 CDM Community Church
        </div>
      </footer>
    `;

    document.body.appendChild(wrapper);

    // Hide other page overlays (home, etc.) so VBS is visible
    setTimeout(function() {
      var homeRoot = document.getElementById('cdm-home-root');
      if (homeRoot) homeRoot.style.display = 'none';
      var sofRoot = document.getElementById('cdm-sof-root');
      if (sofRoot) sofRoot.style.display = 'none';
      var joinRoot = document.getElementById('cdm-join-root');
      if (joinRoot) joinRoot.style.display = 'none';
      var giveRoot = document.getElementById('cdm-give-root');
      if (giveRoot) giveRoot.style.display = 'none';
    }, 100);

    // Mobile drawer
    setTimeout(function () {
      var btn = wrapper.querySelector('.vbs-hamburger');
      if (!btn) return;

      var drawer = document.createElement('div');
      drawer.id = 'vbs-drawer';
      drawer.style.cssText = 'display:none;position:fixed;inset:0;background:#000;z-index:2147483646;flex-direction:column;justify-content:center;align-items:center;gap:0;';

      var closeBtn = document.createElement('button');
      closeBtn.textContent = '\u00d7';
      closeBtn.setAttribute('aria-label', 'Close menu');
      closeBtn.style.cssText = 'position:absolute;top:20px;right:24px;background:none;border:none;color:#fff;font-size:44px;cursor:pointer;line-height:1;font-weight:300;';
      drawer.appendChild(closeBtn);

      var links = [
        { label: 'Home', href: '/' },
        { label: 'Statement of Faith', href: '/about' },
        { label: 'Join Us', href: '/join-us' },
        { label: 'CDM Sports', href: '/cdmsports' },
        { label: 'Give', href: '/give' },
      ];
      links.forEach(function (l) {
        var a = document.createElement('a');
        a.href = l.href;
        a.textContent = l.label;
        a.style.cssText = 'color:#fff;text-decoration:none;font-family:Barlow Condensed,sans-serif;font-weight:900;font-size:clamp(32px,9vw,52px);text-transform:uppercase;letter-spacing:0.04em;border-bottom:1px solid rgba(255,255,255,0.08);width:100%;text-align:center;padding:18px 0;';
        drawer.appendChild(a);
      });

      var giveBtn = document.createElement('a');
      giveBtn.href = '/give';
      giveBtn.textContent = 'GIVE';
      giveBtn.style.cssText = 'margin-top:28px;background:#1E2A5E;color:#fff;font-family:Barlow Condensed,sans-serif;font-weight:900;font-size:20px;letter-spacing:0.12em;padding:14px 52px;border-radius:100px;text-decoration:none;';
      drawer.appendChild(giveBtn);
      wrapper.appendChild(drawer);

      function openDrawer()  { drawer.style.display = 'flex'; btn.setAttribute('aria-expanded','true'); }
      function closeDrawer() { drawer.style.display = 'none';  btn.setAttribute('aria-expanded','false'); }

      btn.addEventListener('click', openDrawer);
      closeBtn.addEventListener('click', closeDrawer);
      drawer.querySelectorAll('a').forEach(function(a){ a.addEventListener('click', closeDrawer); });
    }, 0);
  }

  waitAndInject();
})();
